#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding consent-to-treatment (13 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_patient_information \
    assessment:references \
    preferred_name:string! \
    gender_identity:string! \
    address:text! \
    telephone:string! \
    email:string! \
    nhs_number:string! \
    hospital_number:string! \
    ward_department:string! \
    consultant_name:string! \
    interpreter_required:string! \
    interpreter_language:string! \
    next_of_kin_name:string! \
    next_of_kin_relationship:string! \
    next_of_kin_telephone:string! \
    --htmx

cargo loco generate scaffold assessment_procedure_details \
    assessment:references \
    procedure_name:string! \
    procedure_description:text! \
    procedure_site:string! \
    procedure_site_details:text! \
    intended_benefit:text! \
    urgency:string! \
    planned_date:date \
    estimated_duration_minutes:int \
    performing_clinician:string! \
    performing_clinician_role:string! \
    supervised_by:string! \
    additional_procedures:text! \
    procedure_notes:text! \
    --htmx

cargo loco generate scaffold assessment_risks_benefits \
    assessment:references \
    common_risks:text! \
    uncommon_risks:text! \
    rare_risks:text! \
    specific_risks_to_patient:text! \
    risk_of_not_having_treatment:text! \
    expected_benefits:text! \
    success_rate_discussed:string! \
    success_rate_details:text! \
    recovery_time_discussed:string! \
    expected_recovery_details:text! \
    limitations_after_procedure:text! \
    follow_up_required:string! \
    follow_up_details:text! \
    risks_benefits_notes:text! \
    --htmx

cargo loco generate scaffold assessment_alternative_treatments \
    assessment:references \
    alternatives_discussed:string! \
    conservative_management_discussed:string! \
    conservative_management_details:text! \
    alternative_procedures_discussed:string! \
    alternative_procedures_details:text! \
    no_treatment_option_discussed:string! \
    no_treatment_consequences:text! \
    patient_preference:text! \
    reason_for_chosen_treatment:text! \
    alternative_treatments_notes:text! \
    --htmx

cargo loco generate scaffold assessment_anesthesia_information \
    assessment:references \
    anesthesia_required:string! \
    anesthesia_type:string! \
    anesthesia_details:text! \
    anesthesia_risks_explained:string! \
    anesthesia_specific_risks:text! \
    fasting_instructions_given:string! \
    fasting_from_time:string! \
    previous_anesthesia_problems:string! \
    previous_anesthesia_problem_details:text! \
    family_anesthesia_problems:string! \
    family_anesthesia_problem_details:text! \
    anesthetist_name:string! \
    anesthesia_notes:text! \
    --htmx

cargo loco generate scaffold assessment_questions_understanding \
    assessment:references \
    patient_had_opportunity_to_ask_questions:string! \
    patient_questions:text! \
    questions_answered_satisfactorily:string! \
    patient_understands_procedure:string! \
    patient_understands_risks:string! \
    patient_understands_alternatives:string! \
    information_leaflet_provided:string! \
    leaflet_reference:string! \
    additional_information_requested:string! \
    additional_information_details:text! \
    time_to_consider_given:string! \
    understanding_notes:text! \
    --htmx

cargo loco generate scaffold assessment_patient_rights \
    assessment:references \
    right_to_withdraw_explained:string! \
    right_to_second_opinion_explained:string! \
    confidentiality_explained:string! \
    data_use_explained:string! \
    consent_to_photography:string! \
    consent_to_teaching:string! \
    consent_to_tissue_storage:string! \
    advance_directive_in_place:string! \
    advance_directive_details:text! \
    lasting_power_of_attorney:string! \
    lpa_details:text! \
    patient_rights_notes:text! \
    --htmx

cargo loco generate scaffold assessment_signature_consent \
    assessment:references \
    patient_has_capacity:string! \
    capacity_assessment_details:text! \
    consent_given_by:string! \
    consent_given_by_name:string! \
    consent_given_by_relationship:string! \
    patient_signature_obtained:string! \
    patient_signature_date:date \
    patient_signature_time:string! \
    clinician_signature_obtained:string! \
    clinician_name:string! \
    clinician_role:string! \
    clinician_gmc_number:string! \
    clinician_signature_date:date \
    witness_required:string! \
    witness_name:string! \
    witness_role:string! \
    witness_signature_date:date \
    consent_form_copy_given:string! \
    signature_consent_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    completeness_status:string! \
    sections_complete:int! \
    sections_total:int! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
